import React, { useContext, useState, useEffect } from 'react';
import { DataContext } from '../context/DataContext';
import axios from 'axios';
import { buildApiUrl } from '../config/api';
import '../styles/AdminUsersAdvanced.css';

function AdminUsersAdvanced() {
  const { users, addUser, deleteUser } = useContext(DataContext);
  const [isAdding, setIsAdding] = useState(false);
  const [selectedUser, setSelectedUser] = useState(null);
  const [userActivity, setUserActivity] = useState(null);
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [blockedUsers, setBlockedUsers] = useState([]);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    role: 'user'
  });

  // Получить онлайн пользователей
  useEffect(() => {
    fetchOnlineUsers();
    const interval = setInterval(fetchOnlineUsers, 5000); // Обновлять каждые 5 секунд
    return () => clearInterval(interval);
  }, []);

  const fetchOnlineUsers = async () => {
    try {
      const token = localStorage.getItem('adminToken');
      const response = await axios.get(buildApiUrl('/analytics/online-users'), {
        headers: token ? { 'X-Admin-Token': token } : {}
      });
      setOnlineUsers(response.data || []);
    } catch (error) {
      console.log('Could not fetch online users');
    }
  };

  const fetchUserActivity = async (userId) => {
    try {
      const token = localStorage.getItem('adminToken');
      const response = await axios.get(buildApiUrl(`/analytics/user/${userId}`), {
        headers: token ? { 'X-Admin-Token': token } : {}
      });
      setUserActivity(response.data);
      setSelectedUser(userId);
    } catch (error) {
      console.error('Error fetching user activity:', error);
      // Создаем mock данные для демонстрации
      setUserActivity({
        user: users.find(u => u.id === userId) || {},
        sessions: [],
        bookviews: [],
        downloads: [],
        total_time: 0,
        last_seen: new Date().toISOString()
      });
      setSelectedUser(userId);
    }
  };

  const handleBlockUser = async (userId, block = true) => {
    try {
      const token = localStorage.getItem('adminToken');
      await axios.post(buildApiUrl(`/admin/users/${userId}/block`),
        { blocked: block },
        { headers: token ? { 'X-Admin-Token': token } : {} }
      );

      if (block) {
        setBlockedUsers([...blockedUsers, userId]);
        alert('Foydalanuvchi bloklandi');
      } else {
        setBlockedUsers(blockedUsers.filter(id => id !== userId));
        alert('Foydalanuvchi blok ochildi');
      }
    } catch (error) {
      // Fallback для локального режима
      if (block) {
        setBlockedUsers([...blockedUsers, userId]);
        alert('Foydalanuvchi bloklandi (lokal)');
      } else {
        setBlockedUsers(blockedUsers.filter(id => id !== userId));
        alert('Foydalanuvchi blok ochildi (lokal)');
      }
    }
  };

  const isUserOnline = (userId) => {
    return onlineUsers.some(u => u.user_id === userId);
  };

  const isUserBlocked = (userId) => {
    return blockedUsers.includes(userId);
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleAddUser = () => {
    if (formData.name && formData.email) {
      addUser(formData);
      setFormData({ name: '', email: '', role: 'user' });
      setIsAdding(false);
    }
  };

  const formatTime = (seconds) => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    if (hours > 0) return `${hours} soat ${minutes} daqiqa`;
    return `${minutes} daqiqa`;
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    return new Date(dateString).toLocaleString('uz-UZ');
  };

  return (
    <div className="admin-users-advanced">
      <div className="admin-header">
        <div>
          <h2>👥 Foydalanuvchilar Boshqaruvi</h2>
          <p className="subtitle">Jami: {users.length} | Onlayn: {onlineUsers.length} | Bloklangan: {blockedUsers.length}</p>
        </div>
        <button className="btn btn-primary" onClick={() => setIsAdding(!isAdding)}>
          {isAdding ? '✖️ Bekor qilish' : '➕ Yangi foydalanuvchi'}
        </button>
      </div>

      {isAdding && (
        <div className="user-form">
          <h3>Yangi Foydalanuvchi Qo'shish</h3>
          <div className="form-grid">
            <div className="form-group">
              <label>👤 Ism:</label>
              <input
                type="text"
                name="name"
                value={formData.name}
                onChange={handleInputChange}
                placeholder="Foydalanuvchi ismi"
              />
            </div>
            <div className="form-group">
              <label>📧 Email:</label>
              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleInputChange}
                placeholder="email@example.com"
              />
            </div>
            <div className="form-group">
              <label>🎭 Rol:</label>
              <select name="role" value={formData.role} onChange={handleInputChange}>
                <option value="user">👤 Oddiy foydalanuvchi</option>
                <option value="admin">👑 Administrator</option>
              </select>
            </div>
          </div>
          <button className="btn btn-success" onClick={handleAddUser}>
            ✔️ Qo'shish
          </button>
        </div>
      )}

      {/* Online Users */}
      <div className="online-users-section">
        <h3>🟢 Hozir Onlayn ({onlineUsers.length})</h3>
        <div className="online-users-list">
          {onlineUsers.map((session, index) => (
            <div key={index} className="online-user-card">
              <div className="online-indicator"></div>
              <span className="user-id">User #{session.user_id || 'Mehmon'}</span>
              <span className="device">{session.device_type}</span>
              <span className="time">{formatDate(session.started_at)}</span>
            </div>
          ))}
          {onlineUsers.length === 0 && (
            <p className="no-data">Hech kim onlayn emas</p>
          )}
        </div>
      </div>

      {/* Users Table */}
      <div className="users-table-container">
        <table className="users-table">
          <thead>
            <tr>
              <th>Status</th>
              <th>ID</th>
              <th>Ism</th>
              <th>Email</th>
              <th>Rol</th>
              <th>Holat</th>
              <th>Harakatlar</th>
            </tr>
          </thead>
          <tbody>
            {users.map(user => (
              <tr key={user.id} className={isUserBlocked(user.id) ? 'blocked' : ''}>
                <td>
                  {isUserOnline(user.id) ? (
                    <span className="status-online">🟢</span>
                  ) : (
                    <span className="status-offline">⚫</span>
                  )}
                </td>
                <td>#{user.id}</td>
                <td>{user.name}</td>
                <td>{user.email}</td>
                <td>
                  <span className={`role-badge ${user.role}`}>
                    {user.role === 'admin' ? '👑 Admin' : '👤 User'}
                  </span>
                </td>
                <td>
                  {isUserBlocked(user.id) ? (
                    <span className="blocked-badge">🚫 Bloklangan</span>
                  ) : (
                    <span className="active-badge">✅ Faol</span>
                  )}
                </td>
                <td className="action-buttons">
                  <button
                    className="btn btn-info btn-sm"
                    onClick={() => fetchUserActivity(user.id)}
                    title="Statistikani ko'rish"
                  >
                    📊
                  </button>

                  {user.role !== 'admin' && (
                    <>
                      {isUserBlocked(user.id) ? (
                        <button
                          className="btn btn-success btn-sm"
                          onClick={() => handleBlockUser(user.id, false)}
                          title="Blokdan chiqarish"
                        >
                          🔓
                        </button>
                      ) : (
                        <button
                          className="btn btn-warning btn-sm"
                          onClick={() => handleBlockUser(user.id, true)}
                          title="Bloklash"
                        >
                          🔒
                        </button>
                      )}

                      <button
                        className="btn btn-danger btn-sm"
                        onClick={() => {
                          if (window.confirm(`${user.name} foydalanuvchini o'chirishga ishonchingiz komilmi?`)) {
                            deleteUser(user.id);
                          }
                        }}
                        title="O'chirish"
                      >
                        🗑️
                      </button>
                    </>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* User Activity Modal */}
      {userActivity && selectedUser && (
        <div className="modal-overlay" onClick={() => setUserActivity(null)}>
          <div className="modal-content user-activity-modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>👤 Foydalanuvchi Statistikasi</h3>
              <button className="modal-close" onClick={() => setUserActivity(null)}>✕</button>
            </div>

            <div className="modal-body">
              <div className="user-info-section">
                <div className="info-card">
                  <div className="info-icon">👤</div>
                  <div>
                    <strong>{userActivity.user.name || 'N/A'}</strong>
                    <p>{userActivity.user.email || 'N/A'}</p>
                  </div>
                </div>

                <div className="info-card">
                  <div className="info-icon">⏱️</div>
                  <div>
                    <strong>Umumiy vaqt</strong>
                    <p>{formatTime(userActivity.total_time || 0)}</p>
                  </div>
                </div>

                <div className="info-card">
                  <div className="info-icon">🕐</div>
                  <div>
                    <strong>Oxirgi tashrif</strong>
                    <p>{formatDate(userActivity.last_seen)}</p>
                  </div>
                </div>
              </div>

              <div className="activity-section">
                <h4>📖 O'qilgan Kitoblar ({userActivity.bookviews?.length || 0})</h4>
                <div className="activity-list">
                  {userActivity.bookviews && userActivity.bookviews.length > 0 ? (
                    userActivity.bookviews.slice(0, 10).map((view, index) => (
                      <div key={index} className="activity-item">
                        <span className="activity-icon">📕</span>
                        <div className="activity-details">
                          <span className="activity-title">Kitob #{view.book_id}</span>
                          <span className="activity-meta">
                            {view.pages_read} sahifa | {formatTime(view.time_spent)}
                          </span>
                        </div>
                        <span className="activity-date">{formatDate(view.created_at)}</span>
                      </div>
                    ))
                  ) : (
                    <p className="no-data">Hech qanday kitob o'qilmagan</p>
                  )}
                </div>
              </div>

              <div className="activity-section">
                <h4>📥 Yuklab Olingan Kitoblar ({userActivity.downloads?.length || 0})</h4>
                <div className="activity-list">
                  {userActivity.downloads && userActivity.downloads.length > 0 ? (
                    userActivity.downloads.slice(0, 10).map((download, index) => (
                      <div key={index} className="activity-item">
                        <span className="activity-icon">⬇️</span>
                        <div className="activity-details">
                          <span className="activity-title">Kitob #{download.book_id}</span>
                          <span className="activity-meta">{download.file_size || 'N/A'}</span>
                        </div>
                        <span className="activity-date">{formatDate(download.downloaded_at)}</span>
                      </div>
                    ))
                  ) : (
                    <p className="no-data">Hech qanday kitob yuklab olinmagan</p>
                  )}
                </div>
              </div>

              <div className="activity-section">
                <h4>🌐 Sessiyalar ({userActivity.sessions?.length || 0})</h4>
                <div className="activity-list">
                  {userActivity.sessions && userActivity.sessions.length > 0 ? (
                    userActivity.sessions.slice(0, 10).map((session, index) => (
                      <div key={index} className="activity-item">
                        <span className="activity-icon">
                          {session.device_type === 'mobile' ? '📱' :
                           session.device_type === 'tablet' ? '📲' : '💻'}
                        </span>
                        <div className="activity-details">
                          <span className="activity-title">
                            {session.browser || 'Unknown'} on {session.os || 'Unknown'}
                          </span>
                          <span className="activity-meta">
                            {session.ip_address || 'N/A'} | {session.device_type}
                          </span>
                        </div>
                        <span className="activity-date">{formatDate(session.started_at)}</span>
                      </div>
                    ))
                  ) : (
                    <p className="no-data">Sessiyalar topilmadi</p>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default AdminUsersAdvanced;
