import React, { useState, useEffect, useContext } from 'react';
import { DataContext } from '../context/DataContext';
import axios from 'axios';
import { buildApiUrl } from '../config/api';
import '../styles/AdminDashboard.css';

function AdminDashboard({ onNavigate }) {
  const { books, orders, users } = useContext(DataContext);
  const [analytics, setAnalytics] = useState(null);
  const [loading, setLoading] = useState(true);
  const [timeRange, setTimeRange] = useState('today');

  useEffect(() => {
    fetchDashboardData();
    const interval = setInterval(fetchDashboardData, 10000); // Update every 10 seconds
    return () => clearInterval(interval);
  }, [timeRange]);

  const fetchDashboardData = async () => {
    try {
      const token = localStorage.getItem('adminToken');
      const response = await axios.get(`${buildApiUrl('/analytics/dashboard')}?range=${timeRange}`, {
        headers: token ? { 'X-Admin-Token': token } : {}
      });
      setAnalytics(response.data);
      setLoading(false);
    } catch (error) {
      // Fallback to local data
      calculateLocalAnalytics();
      setLoading(false);
    }
  };

  const calculateLocalAnalytics = () => {
    const totalRevenue = orders.reduce((sum, order) => sum + parseFloat(order.total || 0), 0);
    const pendingOrders = orders.filter(o => o.status === 'pending').length;
    const completedOrders = orders.filter(o => o.status === 'completed').length;
    const lowStockBooks = books.filter(b => b.stock < 10).length;

    setAnalytics({
      total_revenue: totalRevenue,
      total_orders: orders.length,
      pending_orders: pendingOrders,
      completed_orders: completedOrders,
      total_books: books.length,
      low_stock_books: lowStockBooks,
      total_users: users.length,
      active_sessions: 0,
      recent_orders: orders.slice(-5).reverse(),
      top_books: books.slice(0, 5),
      revenue_trend: []
    });
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('uz-UZ').format(amount) + ' UZS';
  };

  const getStatusColor = (status) => {
    switch(status) {
      case 'pending': return '#f39c12';
      case 'processing': return '#3498db';
      case 'completed': return '#27ae60';
      case 'cancelled': return '#e74c3c';
      default: return '#95a5a6';
    }
  };

  const getStatusText = (status) => {
    switch(status) {
      case 'pending': return 'Kutilmoqda';
      case 'processing': return 'Jarayonda';
      case 'completed': return 'Bajarildi';
      case 'cancelled': return 'Bekor qilindi';
      default: return status;
    }
  };

  if (loading) {
    return (
      <div className="dashboard-loading">
        <div className="loading-spinner"></div>
        <p>Dashboard yuklanmoqda...</p>
      </div>
    );
  }

  if (!analytics) return null;

  const handleQuickAction = (action) => {
    if (!onNavigate) {
      console.warn('onNavigate prop not provided to AdminDashboard');
      return;
    }

    switch(action) {
      case 'add-book':
        onNavigate('books');
        break;
      case 'add-user':
        onNavigate('users');
        break;
      case 'export-report':
        // Экспорт данных в CSV
        exportDataToCSV();
        break;
      case 'settings':
        onNavigate('settings');
        break;
      default:
        break;
    }
  };

  const exportDataToCSV = () => {
    try {
      // Создаем CSV с данными аналитики
      const csvData = [
        ['Метрика', 'Значение'],
        ['Общий доход', analytics?.total_revenue || 0],
        ['Всего заказов', analytics?.total_orders || 0],
        ['Всего книг', analytics?.total_books || 0],
        ['Всего пользователей', analytics?.total_users || 0],
        ['Активные сессии', analytics?.active_sessions || 0]
      ];

      const csvContent = csvData.map(row => row.join(',')).join('\n');
      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
      const link = document.createElement('a');
      const url = URL.createObjectURL(blob);

      link.setAttribute('href', url);
      link.setAttribute('download', `analytics_report_${new Date().toISOString().split('T')[0]}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

      alert('Hisobot muvaffaqiyatli yuklandi!');
    } catch (error) {
      console.error('Export error:', error);
      alert('Hisobot eksport qilishda xatolik yuz berdi');
    }
  };

  return (
    <div className="admin-dashboard">
      <div className="dashboard-header">
        <div>
          <h2>📊 Bosh Panel</h2>
          <p className="dashboard-subtitle">Saytingizning real vaqt statistikasi</p>
        </div>
        <div className="time-range-selector">
          <button
            className={timeRange === 'today' ? 'active' : ''}
            onClick={() => setTimeRange('today')}
          >
            Bugun
          </button>
          <button
            className={timeRange === 'week' ? 'active' : ''}
            onClick={() => setTimeRange('week')}
          >
            Hafta
          </button>
          <button
            className={timeRange === 'month' ? 'active' : ''}
            onClick={() => setTimeRange('month')}
          >
            Oy
          </button>
          <button
            className={timeRange === 'year' ? 'active' : ''}
            onClick={() => setTimeRange('year')}
          >
            Yil
          </button>
        </div>
      </div>

      {/* Main Stats */}
      <div className="stats-grid-large">
        <div className="stat-card-large revenue">
          <div className="stat-icon-large">💰</div>
          <div className="stat-details">
            <h3>{formatCurrency(analytics.total_revenue || 0)}</h3>
            <p>Umumiy daromad</p>
            <span className="stat-trend positive">↑ 12.5%</span>
          </div>
        </div>

        <div className="stat-card-large orders">
          <div className="stat-icon-large">📦</div>
          <div className="stat-details">
            <h3>{analytics.total_orders || 0}</h3>
            <p>Buyurtmalar</p>
            <div className="mini-stats">
              <span className="mini-stat pending">⏳ {analytics.pending_orders || 0} kutilmoqda</span>
              <span className="mini-stat completed">✅ {analytics.completed_orders || 0} bajarildi</span>
            </div>
          </div>
        </div>

        <div className="stat-card-large books">
          <div className="stat-icon-large">📚</div>
          <div className="stat-details">
            <h3>{analytics.total_books || 0}</h3>
            <p>Kitoblar</p>
            {analytics.low_stock_books > 0 && (
              <span className="stat-warning">⚠️ {analytics.low_stock_books} kam qoldi</span>
            )}
          </div>
        </div>

        <div className="stat-card-large users">
          <div className="stat-icon-large">👥</div>
          <div className="stat-details">
            <h3>{analytics.total_users || 0}</h3>
            <p>Foydalanuvchilar</p>
            <span className="stat-info">🟢 {analytics.active_sessions || 0} onlayn</span>
          </div>
        </div>
      </div>

      {/* Charts Row */}
      <div className="charts-row">
        <div className="chart-card">
          <h3>📈 Daromad Tendensiyasi</h3>
          <div className="simple-chart">
            {analytics.revenue_trend && analytics.revenue_trend.length > 0 ? (
              <div className="bar-chart">
                {analytics.revenue_trend.map((item, index) => (
                  <div key={index} className="bar-item">
                    <div
                      className="bar"
                      style={{height: `${(item.revenue / Math.max(...analytics.revenue_trend.map(i => i.revenue))) * 100}%`}}
                    >
                      <span className="bar-value">{formatCurrency(item.revenue)}</span>
                    </div>
                    <span className="bar-label">{item.date}</span>
                  </div>
                ))}
              </div>
            ) : (
              <div className="no-data">📊 Ma'lumot yo'q</div>
            )}
          </div>
        </div>

        <div className="chart-card">
          <h3>📊 Buyurtmalar Holati</h3>
          <div className="donut-chart">
            <div className="donut-stats">
              <div className="donut-stat">
                <div className="donut-color" style={{background: '#f39c12'}}></div>
                <span>Kutilmoqda: {analytics.pending_orders || 0}</span>
              </div>
              <div className="donut-stat">
                <div className="donut-color" style={{background: '#3498db'}}></div>
                <span>Jarayonda: {analytics.processing_orders || 0}</span>
              </div>
              <div className="donut-stat">
                <div className="donut-color" style={{background: '#27ae60'}}></div>
                <span>Bajarildi: {analytics.completed_orders || 0}</span>
              </div>
              <div className="donut-stat">
                <div className="donut-color" style={{background: '#e74c3c'}}></div>
                <span>Bekor: {analytics.cancelled_orders || 0}</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Recent Activity */}
      <div className="activity-row">
        <div className="activity-card">
          <h3>🕐 So'nggi Buyurtmalar</h3>
          <div className="recent-orders-list">
            {analytics.recent_orders && analytics.recent_orders.length > 0 ? (
              analytics.recent_orders.map(order => (
                <div key={order.id} className="order-item">
                  <div className="order-info">
                    <span className="order-id">#{order.id}</span>
                    <span className="order-items">
                      {order.items ? `${order.items.length} ta kitob` : 'Ma\'lumot yo\'q'}
                    </span>
                  </div>
                  <div className="order-details">
                    <span className="order-total">{formatCurrency(order.total)}</span>
                    <span
                      className="order-status"
                      style={{background: getStatusColor(order.status)}}
                    >
                      {getStatusText(order.status)}
                    </span>
                  </div>
                </div>
              ))
            ) : (
              <div className="no-data">📭 Buyurtmalar yo'q</div>
            )}
          </div>
        </div>

        <div className="activity-card">
          <h3>🔥 Top Kitoblar</h3>
          <div className="top-books-list">
            {analytics.top_books && analytics.top_books.length > 0 ? (
              analytics.top_books.map((book, index) => (
                <div key={book.id} className="top-book-item">
                  <span className="book-rank">#{index + 1}</span>
                  <span className="book-cover">{book.cover || '📕'}</span>
                  <div className="book-info">
                    <span className="book-title">{book.title}</span>
                    <span className="book-author">{book.author}</span>
                  </div>
                  <div className="book-stats">
                    <span className="book-stock">📦 {book.stock}</span>
                    <span className="book-price">{formatCurrency(book.price)}</span>
                  </div>
                </div>
              ))
            ) : (
              <div className="no-data">📚 Kitoblar yo'q</div>
            )}
          </div>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="quick-actions">
        <h3>⚡ Tezkor Harakatlar</h3>
        <div className="actions-grid">
          <button className="action-btn" onClick={() => handleQuickAction('add-book')}>
            <span className="action-icon">➕</span>
            <span>Yangi Kitob</span>
          </button>
          <button className="action-btn" onClick={() => handleQuickAction('add-user')}>
            <span className="action-icon">👥</span>
            <span>Foydalanuvchi Qo'shish</span>
          </button>
          <button className="action-btn" onClick={() => handleQuickAction('export-report')}>
            <span className="action-icon">📊</span>
            <span>Hisobot Eksport</span>
          </button>
          <button className="action-btn" onClick={() => handleQuickAction('settings')}>
            <span className="action-icon">⚙️</span>
            <span>Sozlamalar</span>
          </button>
        </div>
      </div>
    </div>
  );
}

export default AdminDashboard;
