import React, { useContext, useState } from 'react';
import { DataContext } from '../context/DataContext';
import { LanguageContext } from '../context/LanguageContext';
import '../styles/AdminBooks.css';

function AdminBooks() {
  const { books, addBook, updateBook, deleteBook, categories } = useContext(DataContext);
  const { t } = useContext(LanguageContext);
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [formData, setFormData] = useState({
    title: '',
    author: '',
    category: 'Классика',
    cover: '📕',
    description: '',
    pdf_data: null
  });

  const emojis = ['📕', '📗', '📙', '📘', '📔', '📓', '📒', '📑'];

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handlePdfChange = (e) => {
    const file = e.target.files[0];
    if (file && file.type === 'application/pdf') {
      const reader = new FileReader();
      reader.onload = (event) => {
        setFormData(prev => ({
          ...prev,
          pdf_data: event.target.result
        }));
      };
      reader.readAsDataURL(file);
    } else {
      alert('Faqat PDF fayllari ruxsat etilgan');
    }
  };

  const handleAddBook = () => {
    if (formData.title && formData.author) {
      addBook({
        ...formData,
        price: 0,
        stock: 1
      });
      setFormData({
        title: '',
        author: '',
        category: 'Классика',
        cover: '📕',
        description: '',
        pdf_data: null
      });
      setIsAdding(false);
    }
  };

  const handleEditBook = (book) => {
    setEditingId(book.id);
    setFormData(book);
  };

  const handleUpdateBook = () => {
    if (editingId) {
      updateBook(editingId, { ...formData, price: 0 });
      setEditingId(null);
      setFormData({
        title: '',
        author: '',
        category: 'Классика',
        cover: '📕',
        description: '',
        pdf_data: null
      });
    }
  };

  return (
    <div className="admin-books">
      <div className="admin-header">
        <h2>{t('booksManagement')} ({books.length})</h2>
        <button
          className="btn btn-primary"
          onClick={() => {
            setIsAdding(!isAdding);
            setEditingId(null);
          }}
        >
          {isAdding ? '✖️ ' + t('cancel') : '➕ ' + t('addBook')}
        </button>
      </div>

      {(isAdding || editingId) && (
        <div className="book-form">
          <h3>{editingId ? t('editBook') : t('addBook')}</h3>
          <div className="form-group">
            <label>{t('title')}:</label>
            <input
              type="text"
              name="title"
              value={formData.title}
              onChange={handleInputChange}
              placeholder={t('title')}
            />
          </div>
          <div className="form-group">
            <label>{t('author')}:</label>
            <input
              type="text"
              name="author"
              value={formData.author}
              onChange={handleInputChange}
              placeholder={t('author')}
            />
          </div>
          <div className="form-group">
            <label>{t('category')}:</label>
            <select
              name="category"
              value={formData.category}
              onChange={handleInputChange}
            >
              {categories.map(cat => (
                <option key={cat} value={cat}>{cat}</option>
              ))}
            </select>
          </div>
          <div className="form-group">
            <label>{t('cover')} (emoji):</label>
            <div className="emoji-selector">
              {emojis.map(emoji => (
                <button
                  key={emoji}
                  className={`emoji-btn ${formData.cover === emoji ? 'active' : ''}`}
                  onClick={() => setFormData(prev => ({ ...prev, cover: emoji }))}
                >
                  {emoji}
                </button>
              ))}
            </div>
          </div>
          <div className="form-group">
            <label>{t('description')}:</label>
            <textarea
              name="description"
              value={formData.description}
              onChange={handleInputChange}
              placeholder={t('description')}
              rows="3"
            />
          </div>
          <div className="form-group">
            <label>📄 PDF Fayl:</label>
            <input
              type="file"
              accept=".pdf"
              onChange={handlePdfChange}
            />
            {formData.pdf_data && <p style={{ color: '#28a745' }}>✓ PDF fayl tanlandi</p>}
          </div>
          <div className="form-actions">
            <button
              className="btn btn-success"
              onClick={editingId ? handleUpdateBook : handleAddBook}
            >
              {editingId ? '💾 ' + t('update') : '✔️ ' + t('add')}
            </button>
            {editingId && (
              <button
                className="btn btn-secondary"
                onClick={() => {
                  setEditingId(null);
                  setFormData({
                    title: '',
                    author: '',
                    category: 'Классика',
                    cover: '📕',
                    description: '',
                    pdf_data: null
                  });
                }}
              >
                {t('cancel')}
              </button>
            )}
          </div>
        </div>
      )}

      <div className="books-table">
        <table>
          <thead>
            <tr>
              <th>{t('cover')}</th>
              <th>{t('title')}</th>
              <th>{t('author')}</th>
              <th>{t('category')}</th>
              <th>📄 PDF</th>
              <th>{t('actions')}</th>
            </tr>
          </thead>
          <tbody>
            {books.map(book => (
              <tr key={book.id}>
                <td>{book.cover}</td>
                <td>{book.title}</td>
                <td>{book.author}</td>
                <td>{book.category}</td>
                <td>
                  {book.has_pdf ? '✓ PDF' : '—'}
                </td>
                <td>
                  <button
                    className="btn btn-edit"
                    onClick={() => handleEditBook(book)}
                  >
                    ✏️ {t('edit')}
                  </button>
                  <button
                    className="btn btn-delete"
                    onClick={() => deleteBook(book.id)}
                  >
                    🗑️ {t('delete')}
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default AdminBooks;
