import React, { useContext, useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { LanguageContext } from '../context/LanguageContext';
import AdminBooks from '../components/AdminBooks';
import AdminCategories from '../components/AdminCategories';
import AdminUsers from '../components/AdminUsers';
import AdminUsersAdvanced from '../components/AdminUsersAdvanced';
import AdminOrders from '../components/AdminOrders';
import AdminAnalytics from '../components/AdminAnalytics';
import AdminAutoImport from '../components/AdminAutoImport';
import AdminPDFLibrary from '../components/AdminPDFLibrary';
import AdminSimpleBooks from '../components/AdminSimpleBooks';
import AdminDashboard from '../components/AdminDashboard';
import AdminSettings from '../components/AdminSettings';
import { buildApiUrl } from '../config/api';
import '../styles/AdminPanel.css';

function AdminPanel() {
  const navigate = useNavigate();
  const { t } = useContext(LanguageContext);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem('adminToken');
    if (token) {
      setIsAuthenticated(true);
    }
  }, []);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const res = await fetch(buildApiUrl('/admin/login'), {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ password })
      });

      if (res.ok) {
        const data = await res.json();
        localStorage.setItem('adminToken', data.token);
        setIsAuthenticated(true);
        setPassword('');
      } else {
        setError('Noto\'g\'ri parol! Qaytadan urinib ko\'ring.');
      }
    } catch (err) {
      console.error(err);
      setError('Server bilan bog\'lanishda xato. Keyinroq urinib ko\'ring.');
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('adminToken');
    setIsAuthenticated(false);
    setPassword('');
    navigate('/');
  };

  // Login form
  if (!isAuthenticated) {
    return (
      <div className="admin-login-container">
        <div className="admin-login-box">
          <div className="login-icon">🔐</div>
          <h1>Admin Panel</h1>
          <p className="login-subtitle">Kirish uchun parolni kiriting</p>
          
          <form onSubmit={handleLogin} className="login-form">
            <div className="form-group">
              <label htmlFor="password">🔑 Parol</label>
              <input
                type="password"
                id="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Admin parolini kiriting"
                required
                autoFocus
              />
            </div>
            
            {error && <div className="error-message">❌ {error}</div>}
            
            <button type="submit" className="btn btn-primary btn-login" disabled={loading}>
              {loading ? '⏳ Tekshirilmoqda...' : '✅ Kirish'}
            </button>
            
            <button type="button" className="btn btn-secondary btn-back" onClick={() => navigate('/')}>
              ← Bosh sahifaga qaytish
            </button>
          </form>
        </div>
      </div>
    );
  }

  // Admin panel
  return (
    <div className="admin-panel">
      <div className="admin-header">
        <h1>⚙️ {t('adminPanel')}</h1>
        <button className="btn btn-logout" onClick={handleLogout}>
          🚪 Chiqish
        </button>
      </div>

      <div className="admin-tabs">
        <button
          className={`tab-btn ${activeTab === 'dashboard' ? 'active' : ''}`}
          onClick={() => setActiveTab('dashboard')}
        >
          📊 Dashboard
        </button>
        <button
          className={`tab-btn ${activeTab === 'analytics' ? 'active' : ''}`}
          onClick={() => setActiveTab('analytics')}
        >
          📈 Analytics
        </button>
        <button
          className={`tab-btn ${activeTab === 'books' ? 'active' : ''}`}
          onClick={() => setActiveTab('books')}
        >
          📚 {t('booksManagement')}
        </button>
        <button
          className={`tab-btn ${activeTab === 'orders' ? 'active' : ''}`}
          onClick={() => setActiveTab('orders')}
        >
          📦 {t('ordersManagement')}
        </button>
        <button
          className={`tab-btn ${activeTab === 'users' ? 'active' : ''}`}
          onClick={() => setActiveTab('users')}
        >
          👥 {t('usersManagement')}
        </button>
        <button
          className={`tab-btn ${activeTab === 'categories' ? 'active' : ''}`}
          onClick={() => setActiveTab('categories')}
        >
          🏷️ {t('categoriesManagement')}
        </button>
        <button
          className={`tab-btn ${activeTab === 'pdflibrary' ? 'active' : ''}`}
          onClick={() => setActiveTab('pdflibrary')}
        >
          📖 PDF Kutubxona
        </button>
        <button
          className={`tab-btn ${activeTab === 'simplebooks' ? 'active' : ''}`}
          onClick={() => setActiveTab('simplebooks')}
        >
          ✅ Demo Kitoblar
        </button>
        <button
          className={`tab-btn ${activeTab === 'autoimport' ? 'active' : ''}`}
          onClick={() => setActiveTab('autoimport')}
        >
          🤖 Avto Yuklash
        </button>
        <button
          className={`tab-btn ${activeTab === 'settings' ? 'active' : ''}`}
          onClick={() => setActiveTab('settings')}
        >
          ⚙️ Sozlamalar
        </button>
      </div>

      <div className="admin-content">
        {activeTab === 'dashboard' && <AdminDashboard onNavigate={setActiveTab} />}
        {activeTab === 'analytics' && <AdminAnalytics />}
        {activeTab === 'books' && <AdminBooks />}
        {activeTab === 'orders' && <AdminOrders />}
        {activeTab === 'users' && <AdminUsersAdvanced />}
        {activeTab === 'categories' && <AdminCategories />}
        {activeTab === 'pdflibrary' && <AdminPDFLibrary />}
        {activeTab === 'simplebooks' && <AdminSimpleBooks />}
        {activeTab === 'autoimport' && <AdminAutoImport />}
        {activeTab === 'settings' && <AdminSettings />}
      </div>
    </div>
  );
}

export default AdminPanel;
